from fastapi import APIRouter, Depends, HTTPException, Form
from fastapi.security import OAuth2PasswordRequestForm
from sqlalchemy.orm import Session
from pydantic import BaseModel, EmailStr
from datetime import datetime, timedelta, timezone
from jose import jwt
from passlib.context import CryptContext
import os

from app.database import get_db
from app.models.user_model import User, UserRoleEnum
from app.models.patient_model import PatientProfile
from app.dependencies import hash_password

SECRET_KEY = os.getenv("SECRET_KEY")
ALGORITHM = os.getenv("ALGORITHM")
ACCESS_TOKEN_EXPIRE_MINUTES = int(os.getenv("ACCESS_TOKEN_EXPIRE_MINUTES") or 30)
pwd_context = CryptContext(schemes=["bcrypt"], deprecated="auto")

router = APIRouter(prefix="/auth", tags=["Auth"])

class RegisterPatientRequest(BaseModel):
    name: str
    email: EmailStr
    password: str

    @classmethod
    def as_form(
        cls,
        name: str = Form(...),
        email: EmailStr = Form(...),
        password: str = Form(...),
    ):
        return cls(
            name=name,
            email=email,
            password=password,
        )

class TokenResponse(BaseModel):
    access_token: str
    token_type: str
    role: str

def verify_password(plain_password, hashed_password):
    return pwd_context.verify(plain_password, hashed_password)

def create_access_token(data: dict):
    to_encode = data.copy()
    expire = datetime.now(timezone.utc) + timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES)
    to_encode.update({"exp": expire})
    return jwt.encode(to_encode, SECRET_KEY, algorithm=ALGORITHM)

@router.post("/register", status_code=201, response_model=TokenResponse)
def register_patient(data: RegisterPatientRequest, db: Session = Depends(get_db)):

    existing_user = db.query(User).filter(User.email == data.email).first()
    if existing_user:
        raise HTTPException(status_code=400, detail="Email already registered")

    # إنشاء User
    user = User(
        name=data.name,
        email=data.email,
        password_hash=hash_password(data.password),
        role=UserRoleEnum.PATIENT
    )
    db.add(user)
    db.commit()
    db.refresh(user)

    patient_profile = PatientProfile(user_id=user.user_id)
    db.add(patient_profile)
    db.commit()

    access_token = create_access_token(data={"sub": str(user.user_id), "role": user.role.value})
    return {"access_token": access_token, "token_type": "bearer", "role": user.role.value}

@router.post("/login", response_model=TokenResponse)
def login_user(form_data: OAuth2PasswordRequestForm = Depends(), db: Session = Depends(get_db)):

    user = db.query(User).filter(User.email == form_data.username).first()
    if not user or not verify_password(form_data.password, user.password_hash):
        raise HTTPException(status_code=401, detail="Invalid email or password")

    if user.role == UserRoleEnum.DOCTOR and not user.doctor_profile:
        raise HTTPException(status_code=403, detail="Doctor profile not found")
    if user.role == UserRoleEnum.SECRETARY and not user.secretary_profile:
        raise HTTPException(status_code=403, detail="Secretary profile not found")
    # Admin doesn't need a profile

    access_token = create_access_token(data={
        "sub": str(user.user_id),
        "role": user.role.value
    })

    return {"access_token": access_token, "token_type": "bearer", "role": user.role.value}

from fastapi import APIRouter, Depends, HTTPException from sqlalchemy.orm import Session, joinedload from sqlalchemy import func from pydantic import BaseModel, Field from typing import Optional, List from app.database import get_db from app.models.doctor_model import DoctorProfile from app.models.appointment_model import Appointment from app.models.diagnosis_model import Diagnosis from app.models.doctorschedule_model import DoctorSchedule
router = APIRouter( prefix="/doctors", tags=["Doctors"] )
# --- Schemas ---
class ClinicHour(BaseModel): day: str start: Optional[str] end: Optional[str]
class Config: from_attributes = True
class DoctorProfileResponse(BaseModel): doctor_id: int name: str photo: Optional[str] = None phone: Optional[str] = None email: Optional[str] = None position: Optional[str] = None yearsOfExperience: Optional[int] = None education: Optional[str] = None clinical_expertise: Optional[str] = None description: Optional[str] = None professionalBiography: Optional[str] = None
starRating: Optional[float] = 0.0 patientReviews: Optional[int] = 0 patientNumbers: Optional[int] = 0 clinicHours: List[ClinicHour] = []
class Config: from_attributes = True
def format_doctor_data(doctor, db: Session):
patient_count = db.query(func.count(Appointment.patient_id)).filter( Appointment.doctor_id == doctor.doctor_id).scalar() reviews_count = db.query(func.count(Diagnosis.diagnosis_id)).filter( Diagnosis.doctor_id == doctor.doctor_id).scalar() avg_rating = db.query(func.avg(Diagnosis.rating)).filter(Diagnosis.doctor_id == doctor.doctor_id).scalar() or 0
schedules = db.query(DoctorSchedule).filter(DoctorSchedule.doctor_id == doctor.doctor_id).all() clinic_hours = [ {"day": s.day_of_week.value, "start": s.start_time.strftime("%H:%M") if s.start_time else None, "end": s.end_time.strftime("%H:%M") if s.end_time else None} for s in schedules ]
return { "doctor_id": doctor.doctor_id, "name": doctor.user.name, "photo": doctor.user.photo, "phone": doctor.user.phone, "email": doctor.user.email, "position": doctor.position, "yearsOfExperience": doctor.years_of_experience, "education": doctor.education, "clinical_expertise": doctor.clinical_expertise, "description": doctor.bio, "professionalBiography": doctor.bio, "starRating": round(avg_rating, 1), "patientReviews": reviews_count, "patientNumbers": patient_count, "clinicHours": clinic_hours }
@router.get("/", response_model=List[DoctorProfileResponse]) def get_all_doctors(db: Session = Depends(get_db)): doctors = db.query(DoctorProfile).options(joinedload(DoctorProfile.user)).all()
return [format_doctor_data(doc, db) for doc in doctors]
@router.get("/{doctor_id}", response_model=DoctorProfileResponse) def view_doctor_profile(doctor_id: int, db: Session = Depends(get_db)): doctor = db.query(DoctorProfile).options(joinedload(DoctorProfile.user)).filter( DoctorProfile.doctor_id == doctor_id ).first()
if not doctor: raise HTTPException(status_code=404, detail="Doctor not found")
return format_doctor_data(doctor, db)
